$ErrorActionPreference='Stop';$script=Join-Path $PSScriptRoot 'resolve-team-policy.ps1';$r=(& $script -Profile regulated -Json|Out-String)|ConvertFrom-Json;if($r.precedence -join ',' -ne 'regulated,enterprise,startup,solo' -or $r.policy.independentReview -ne 'required' -or $r.automaticMutation){throw 'Team policy resolution failed.'};$strict=(& $script -Profile strict-scope -Json|Out-String)|ConvertFrom-Json;if($strict.precedence -join ',' -ne 'strict-scope,solo' -or $strict.policy.delegation -ne 'explicit-independent-benefit-only' -or $strict.policy.autonomousUpgrades -ne 'forbidden-without-explicit-request'){throw 'Strict-scope team policy resolution failed.'};Write-Host 'Team policy tests passed'
